What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void main() {
    int x = 55, y = 5;
    switch(x % 7){
        case 0: case 1: y++;
        case 2: case 3: y = y + 2;
        case 4: break;
        case 5: case 6: y = y - 3;
    }
    cout << y << endl;
}
```

What is the final value of x?

```cpp
#include <iostream>
using namespace std;
void main() {
    int x, y = 5;
    x = y++ + --y;
    cout << x << endl;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
int f1(int a) {
    a++;
    return a;
}
void main() {
    cout << f1(f1(2));
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
double f1(double x, int y) {
    cout << "hi1";
    return 7.59;
}
int f1(int x, int b) {
    cout << "hi2";
    return 6;
}
int main() {
    double z = f1(7.4, 5);
    cout << z << endl;
    return 0;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
int x = 15;
void function(int &k) {
    k += 3;
}
void main() {
    int x = 7;
    function(x);
    cout << x << endl;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void a() {
    cout << "b" << endl;
}
void b() {
    cout << "a" << endl;
}
void main() {
    bool h = 1;
    if(h)
        a();
    else
        b();
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
int f2(int s) {
    return ++s + 3;
}
void f1(char ch) {
    if (ch > 'a')
        cout << f2(4) << endl;
    else
        cout << f2(6) << endl;
}
int main() {
    f1('D');
    return 0;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
int p = 6;
void f1() {
    p += 2;
}
void f2() {
    int p = 2;
    p += 2;
    cout << p;
    ::p += 3;
}
void main() {
    p += 2;
    f1();
    cout << p;
    f2();
    cout << p << endl;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
int x = 7;
void fun(int l) {
    static int x = 2;
    x += 1;
    cout << x;
}
void main() {
    for(int r = 0 ; r < 3 ; ++r)
        fun(r);
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void main() {
    int i;
    for(i = 1 ; i < 5 ; i++)
        for(int j = i ; j > 2 ; j--)
            cout << j + i;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void main() {
    int u = 5;
    while(u >= 1) {
        int b = 10;
        for( ; b >= 1 ; b -= 3) {
            if(b % 2 == 0)
                continue;
            cout << b;
        }
        u -= 4;
    }
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
bool f3(int x) {
    if(x > 3)
        return 5;
    return false;
}

void main() {
    int b = f3(6);
    cout << b << endl;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void main() {
    int var = 46;
    do {
        var = var / 4;
        if(var == 0)
            break;
        cout << var;
    } while(var <= 20);
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
double G5(int &x, int y = 15, double z = 3.25) {
    x += 2;
    return x + y + z;
}

void main() {
    int d = 8;
    cout << G5(d, 2) << " ";
    cout << d << endl;
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void main() {
    for(int i = 1, j = 5 ; i > 6 && j >= 2 ; ++i, j--)
        if(i % 2 == 0)
            cout << "*";
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void main() {
    int i = 7;
    for(i = 6 ; i >= 3 ; i -= 2) ;
        for(int j = 1 ; j < 3 ; j++) ;
            cout << "hi" << i;
}
```
